import{c as o,Q as r,j as e,m as a}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Boris Cherny on Verification Loops","description":"","frontmatter":{"url":"https://x.com/bcherny/status/2007179861115511237","date":"2026-05-12T00:00:00.000Z","scored":"2026-05-16T00:00:00.000Z","source":"Twitter/X — Boris Cherny (@bcherny)","source_file":"../2026-05-12-boris-cherny-verification-loops.md","source_tier":"C","tags":["verification-loops","quality-multiplier","stop-hooks","bcherny","claude-code-creator"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-12-boris-cherny-verification-loops.md","filePath":"research/ai-articles/scored/2026-05-12-boris-cherny-verification-loops.md","lastUpdated":1779894392000}'),i={name:"research/ai-articles/scored/2026-05-12-boris-cherny-verification-loops.md"};function s(d,t,l,n,c,h){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="boris-cherny-on-verification-loops" tabindex="-1">Boris Cherny on Verification Loops <a class="header-anchor" href="#boris-cherny-on-verification-loops" aria-label="Permalink to &quot;Boris Cherny on Verification Loops&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://x.com/bcherny/status/2007179861115511237" target="_blank" rel="noreferrer">https://x.com/bcherny/status/2007179861115511237</a><br><strong>作者</strong>：Boris Cherny（Claude Code 創建者，Anthropic）</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Claude Code 創建者 Boris Cherny 的直接建議：給 Claude 驗證自己工作的機制，是提升輸出品質「最重要的一件事」，可達 2-3x 品質提升。不是工具選擇、不是 prompt 技巧——是驗證迴路。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><blockquote><p>&quot;A final tip: probably the most important thing to get great results out of Claude Code — give Claude a way to verify its work. If Claude has that feedback loop, it will 2-3x the quality of the final result.&quot;</p></blockquote><ul><li><strong>2-3x 品質提升</strong>：有 feedback loop vs 無 feedback loop 的差距</li><li><strong>驗證形式</strong>：跑測試、bash 指令、UI 截圖比對、任何能判斷「是否正確」的機制</li><li><strong>實際應用</strong>：Stop hooks 做確定性驗證；background agents 做長任務驗證；/loop 做定期驗證</li></ul><hr><h2 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h2><ul><li><code>core.md § 驗證與品質</code> 已有 R4 goal-oriented 原則，但缺乏「2-3x」的量化錨點</li><li>此推文提供第一手實測依據，可強化「驗證是最高槓桿操作」的論述</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>Stop hooks + background agent 驗證模式可直接套用；「2-3x」量化錨點強化現有 R4</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>cc-workspace core.md R4 已有驗證原則；此文主要提供一手量化依據，非全新概念</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>直接引用 Claude Code 創建者；「2-3x」為個人實測斷言，無控制實驗（上限 6/10 for anecdote）</td></tr><tr><td>D. 技術深度</td><td>4/10</td><td>推文格式，具體度有限；Stop hooks / background agent 僅提及，無實作細節</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>驗證迴路原則適用所有 Claude Code workflow，不限特定任務類型</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.6/10</strong></td><td>8×0.3 + 6×0.2 + 6×0.2 + 4×0.15 + 8×0.15 = 2.40+1.20+1.20+0.60+1.20</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（驗證原則補充到現有規則，非新增 Skill）<br><strong>整合位置</strong>：<code>.claude/rules/core.md</code> § 驗證與品質 — 補充「2-3x 品質乘數」量化錨點與 Stop hook 驗證建議<br><strong>整合狀態</strong>：待實作</p><hr><h2 id="todo" tabindex="-1">TODO <a class="header-anchor" href="#todo" aria-label="Permalink to &quot;TODO&quot;">​</a></h2><ul><li>[ ] 在 <code>.claude/rules/core.md</code> § 驗證與品質段落，加入 bcherny 的量化引用（2-3x quality from verification loop）</li><li>[ ] 確認 Stop hooks 驗證模式已在 workspace 設定（settings.json hooks 區塊）</li></ul>',19)])])}const b=o(i,[["render",s]]);export{u as __pageData,b as default};
